  async up(queryInterface, Sequelize) {
    await queryInterface.createTable("device_tokens", {
      id: { type: Sequelize.INTEGER, primaryKey: true, autoIncrement: true },
      usuarioId: {
        type: Sequelize.INTEGER,
        allowNull: false,
        references: { model: "usuarios", key: "id" },
        onUpdate: "CASCADE",
        onDelete: "CASCADE"
      },
      token: { type: Sequelize.STRING(512), allowNull: false, unique: true },
      platform: { type: Sequelize.STRING(32), allowNull: false, defaultValue: "android" },
      isActive: { type: Sequelize.BOOLEAN, allowNull: false, defaultValue: true },
      lastSeenAt: { type: Sequelize.DATE, allowNull: false, defaultValue: Sequelize.literal("CURRENT_TIMESTAMP") },
      createdAt: { type: Sequelize.DATE, allowNull: false, defaultValue: Sequelize.literal("CURRENT_TIMESTAMP") },
      updatedAt: { type: Sequelize.DATE, allowNull: false, defaultValue: Sequelize.literal("CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP") }
    });

    await queryInterface.addIndex("device_tokens", ["usuarioId"]);
    await queryInterface.addIndex("device_tokens", ["isActive"]);
  },

  async down(queryInterface) {
    await queryInterface.dropTable("device_tokens");
  }
};

const horarioService = require('../services/horarioService');

async function create(req, res) {
  try {
    const usuarioId = req.user.id;
    const payload = { ...req.body, usuarioId };
    const horario = await horarioService.createHorario(payload);
    res.status(201).json(horario);
  } catch (err) {
    res.status(400).json({ error: err.message });
  }
}

async function list(req, res) {
  try {
    const usuarioId = req.user.id;
    const items = await horarioService.listHorarios(usuarioId);
    res.json(items);
  } catch (err) {
    res.status(400).json({ error: err.message });
  }
}

async function update(req, res) {
  try {
    const usuarioId = req.user.id;
    const { id } = req.params;
    const updated = await horarioService.updateHorario(id, usuarioId, req.body);
    if (!updated) return res.status(404).json({ error: 'Not found' });
    res.json(updated);
  } catch (err) {
    res.status(400).json({ error: err.message });
  }
}

async function remove(req, res) {
  try {
    const usuarioId = req.user.id;
    const { id } = req.params;
    const ok = await horarioService.deleteHorario(id, usuarioId);
    if (!ok) return res.status(404).json({ error: 'Not found' });
