  try {
    const usuarioId = req.user.id;
    const materiaId = req.query.materiaId || null;
    const items = await imagenService.listImagenes(usuarioId, materiaId);
    res.json(items);
  } catch (err) {
    res.status(400).json({ error: err.message });
  }
}

