package com.example.organizadoracademico.presentation.horario.crear

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.organizadoracademico.data.local.util.SessionManager // <-- Importante
import com.example.organizadoracademico.domain.model.Horario
import com.example.organizadoracademico.domain.usercase.horario.AddHorarioUseCase
import com.example.organizadoracademico.domain.usercase.materia.GetMateriasUseCase
import com.example.organizadoracademico.domain.usercase.profesor.GetProfesoresUseCase
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.catch
import kotlinx.coroutines.flow.combine
import kotlinx.coroutines.flow.launchIn
import kotlinx.coroutines.flow.onEach
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch

class CrearHorarioViewModel(
    private val getMateriasUseCase: GetMateriasUseCase,
    private val getProfesoresUseCase: GetProfesoresUseCase,
    private val addHorarioUseCase: AddHorarioUseCase,
    private val sessionManager: SessionManager // <-- 1. Inyectamos el SessionManager
) : ViewModel() {

    private val _state = MutableStateFlow(CrearHorarioState())
    val state: StateFlow<CrearHorarioState> = _state.asStateFlow()

    // 2. Obtenemos el ID del usuario actual
    private val userId = sessionManager.getUserId()

    init {
        cargarDatosIniciales()
    }

    // ... (onEvent y cargarDatosIniciales se mantienen igual)
    fun onEvent(event: CrearHorarioEvent) {
        when (event) {
            is CrearHorarioEvent.CargarDatosIniciales -> cargarDatosIniciales()
            is CrearHorarioEvent.SeleccionarMateria -> {
                _state.update { it.copy(materiaSeleccionada = event.materia) }
            }
            is CrearHorarioEvent.SeleccionarProfesor -> {
                _state.update { it.copy(profesorSeleccionado = event.profesor) }
            }
            is CrearHorarioEvent.SeleccionarDia -> {
                _state.update { it.copy(diaSeleccionado = event.dia) }
            }
            is CrearHorarioEvent.SeleccionarHoraInicio -> {
                _state.update { it.copy(horaInicio = event.hora) }
            }
            is CrearHorarioEvent.SeleccionarHoraFin -> {
                _state.update { it.copy(horaFin = event.hora) }
            }
            is CrearHorarioEvent.SeleccionarColor -> {
                _state.update { it.copy(colorSeleccionado = event.color) }
            }
            is CrearHorarioEvent.GuardarHorario -> guardarHorario()
            is CrearHorarioEvent.ResetSuccess -> {
                _state.update { it.copy(isSuccess = false) }
            }
        }
    }

    private fun cargarDatosIniciales() {
        _state.update { it.copy(isLoading = true) }

        val materiasFlow = getMateriasUseCase()
        val profesoresFlow = getProfesoresUseCase()

        combine(materiasFlow, profesoresFlow) { materias, profesores ->
            Pair(materias, profesores)
        }.onEach { (materias, profesores) ->
            _state.update {
                it.copy(
                    materias = materias,
                    profesores = profesores,
                    isLoading = false
                )
            }
        }.catch { e ->
            _state.update {
                it.copy(
                    isLoading = false,
                    errorMessage = "Error al cargar datos: ${e.message}"
                )
            }
        }.launchIn(viewModelScope)
    }

    private fun guardarHorario() {
        viewModelScope.launch {
            val materia = _state.value.materiaSeleccionada
            val profesor = _state.value.profesorSeleccionado

            if (materia == null || profesor == null) {
                _state.update { it.copy(errorMessage = "Debes seleccionar materia y profesor") }
                return@launch
            }

            if (_state.value.horaInicio >= _state.value.horaFin) {
                _state.update { it.copy(errorMessage = "La hora fin debe ser mayor a la hora inicio") }
                return@launch
            }

            _state.update { it.copy(isLoading = true, errorMessage = null) }

            // 3. AGREGAMOS EL usuarioId AL CONSTRUCTOR DEL HORARIO
            val horario = Horario(
                usuarioId = userId, // <-- Aquí se soluciona el error
                materiaId = materia.id,
                profesorId = profesor.id,
                dia = _state.value.diaSeleccionado,
                horaInicio = _state.value.horaInicio,
                horaFin = _state.value.horaFin,
                color = _state.value.colorSeleccionado
            )

            val result = addHorarioUseCase.invoke(horario)

            result.onSuccess {
                _state.update { it.copy(isLoading = false, isSuccess = true) }
            }.onFailure { exception ->
                _state.update {
                    it.copy(isLoading = false, errorMessage = exception.message ?: "Error al guardar")
                }
            }
        }
    }
}

package com.example.organizadoracademico.presentation.horario.crear

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.organizadoracademico.data.local.util.SessionManager
import com.example.organizadoracademico.domain.model.Horario
import com.example.organizadoracademico.domain.usercase.horario.AddHorarioUseCase
import com.example.organizadoracademico.domain.usercase.horario.GetHorariosUseCase
import com.example.organizadoracademico.domain.usercase.materia.GetMateriasUseCase
import com.example.organizadoracademico.domain.usercase.profesor.GetProfesoresUseCase
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.catch
import kotlinx.coroutines.flow.combine
import kotlinx.coroutines.flow.launchIn
import kotlinx.coroutines.flow.onEach
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch

class CrearHorarioViewModel(
    private val getMateriasUseCase: GetMateriasUseCase,
    private val getProfesoresUseCase: GetProfesoresUseCase,
    private val getHorariosUseCase: GetHorariosUseCase,
    private val addHorarioUseCase: AddHorarioUseCase,
    private val sessionManager: SessionManager
) : ViewModel() {

    private val _state = MutableStateFlow(CrearHorarioState())
    val state: StateFlow<CrearHorarioState> = _state.asStateFlow()

    private val userId = sessionManager.getUserId()
    private var horariosExistentes: List<Horario> = emptyList()

    init {
        cargarDatosIniciales()
    }

    // ... (onEvent se mantiene igual)
    fun onEvent(event: CrearHorarioEvent) {
        when (event) {
            is CrearHorarioEvent.CargarDatosIniciales -> cargarDatosIniciales()
            is CrearHorarioEvent.SeleccionarMateria -> {
                _state.update { it.copy(materiaSeleccionada = event.materia) }
            }
            is CrearHorarioEvent.SeleccionarProfesor -> {
                _state.update { it.copy(profesorSeleccionado = event.profesor) }
            }
            is CrearHorarioEvent.SeleccionarDia -> {
                _state.update { it.copy(diaSeleccionado = event.dia) }
            }
            is CrearHorarioEvent.SeleccionarHoraInicio -> {
                _state.update { it.copy(horaInicio = event.hora) }
            }
            is CrearHorarioEvent.SeleccionarHoraFin -> {
                _state.update { it.copy(horaFin = event.hora) }
            }
            is CrearHorarioEvent.SeleccionarColor -> {
                _state.update { it.copy(colorSeleccionado = event.color) }
            }
            is CrearHorarioEvent.GuardarHorario -> guardarHorario()
            is CrearHorarioEvent.ResetSuccess -> {
                _state.update { it.copy(isSuccess = false) }
            }
        }
    }

    private fun cargarDatosIniciales() {
        _state.update { it.copy(isLoading = true) }

        val materiasFlow = getMateriasUseCase()
        val profesoresFlow = getProfesoresUseCase()
        val horariosFlow = getHorariosUseCase(userId)

        combine(materiasFlow, profesoresFlow, horariosFlow) { materias, profesores, horarios ->
            Triple(materias, profesores, horarios)
        }.onEach { (materias, profesores, horarios) ->
            horariosExistentes = horarios
            _state.update {
                it.copy(
                    materias = materias,
                    profesores = profesores,
                    isLoading = false
                )
            }
        }.catch { e ->
            _state.update {
                it.copy(
                    isLoading = false,
                    errorMessage = "Error al cargar datos: ${e.message}"
                )
            }
        }.launchIn(viewModelScope)
    }

    private fun guardarHorario() {
        viewModelScope.launch {
            val materia = _state.value.materiaSeleccionada
            val profesor = _state.value.profesorSeleccionado

            if (materia == null || profesor == null) {
                _state.update { it.copy(errorMessage = "Debes seleccionar materia y profesor") }
                return@launch
            }

            if (_state.value.horaInicio >= _state.value.horaFin) {
                _state.update { it.copy(errorMessage = "La hora fin debe ser mayor a la hora inicio") }
                return@launch
            }

            if (hasOverlap(_state.value.diaSeleccionado, _state.value.horaInicio, _state.value.horaFin)) {
                _state.update { it.copy(errorMessage = "Ese horario se traslapa con otra clase existente") }
                return@launch
            }

            _state.update { it.copy(isLoading = true, errorMessage = null) }

            val horario = Horario(
                usuarioId = userId,
                materiaId = materia.id,
                profesorId = profesor.id,
                dia = _state.value.diaSeleccionado,
                horaInicio = _state.value.horaInicio,
                horaFin = _state.value.horaFin,
                color = _state.value.colorSeleccionado
            )

            val result = addHorarioUseCase.invoke(horario)

            result.onSuccess {
                _state.update { it.copy(isLoading = false, isSuccess = true) }
            }.onFailure { exception ->
                _state.update {
                    it.copy(isLoading = false, errorMessage = exception.message ?: "Error al guardar")
                }
            }
        }
    }

    private fun hasOverlap(dia: String, horaInicio: String, horaFin: String): Boolean {
        val newStart = toMinutes(horaInicio) ?: return false
        val newEnd = toMinutes(horaFin) ?: return false

        return horariosExistentes
            .asSequence()
            .filter { it.dia.equals(dia, ignoreCase = true) }
            .any { existing ->
                val existingStart = toMinutes(existing.horaInicio) ?: return@any false
                val existingEnd = toMinutes(existing.horaFin) ?: return@any false
                newStart < existingEnd && newEnd > existingStart
            }
    }

    private fun toMinutes(hourText: String): Int? {
        val parts = hourText.split(":")
        if (parts.size != 2) return null

        val h = parts[0].trim().toIntOrNull() ?: return null
        val m = parts[1].trim().toIntOrNull() ?: return null
        if (h !in 0..23 || m !in 0..59) return null

        return h * 60 + m
    }
}

package com.example.organizadoracademico.presentation.horario.ver

import androidx.compose.foundation.background
import androidx.compose.foundation.clickable
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.draw.clip
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import androidx.navigation.NavController
import com.example.organizadoracademico.presentation.theme.*
import com.example.organizadoracademico.presentation.animation.pulseEffect
import org.koin.androidx.compose.koinViewModel

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun VerHorarioScreen(
    navController: NavController,
    viewModel: VerHorarioViewModel = koinViewModel()
) {
    val state by viewModel.state.collectAsState()

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("MI HORARIO", color = TextoBlanco) },
                navigationIcon = {
                    IconButton(onClick = { navController.popBackStack() }) {
                        Text("←", fontSize = 24.sp, color = TextoBlanco)
                    }
                },
                colors = TopAppBarDefaults.topAppBarColors(
                    containerColor = SuperficieCards
                )
            )
        }
    ) { paddingValues ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .background(FondoPrincipal)
                .padding(paddingValues)
        ) {
            // Selector de días
            DiasSemanaRow(
                dias = state.diasSemana,
                diaSeleccionado = state.diaSeleccionado,
                onDiaClick = { dia ->
                    viewModel.onEvent(VerHorarioEvent.SeleccionarDia(dia))
                }
            )

            Spacer(modifier = Modifier.height(16.dp))

            // Línea decorativa
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .height(1.dp)
                    .background(BordeNeon)
            )

            // Lista de horarios
            if (state.isLoading) {
                Box(
                    modifier = Modifier.fillMaxSize(),
                    contentAlignment = Alignment.Center
                ) {
                    CircularProgressIndicator(color = MoradoNeon)
                }
            } else {
                HorariosPorDia(
                    viewModel = viewModel,
                    dia = state.diaSeleccionado
                )
            }
        }
    }
}

@Composable
fun DiasSemanaRow(
    dias: List<String>,
    diaSeleccionado: String,
    onDiaClick: (String) -> Unit
) {
    Row(
        modifier = Modifier
            .fillMaxWidth()
            .padding(horizontal = 16.dp, vertical = 12.dp),
        horizontalArrangement = Arrangement.SpaceEvenly
    ) {
        dias.forEach { dia ->
            val isSelected = dia == diaSeleccionado
            Box(
                modifier = Modifier
                    .clip(RoundedCornerShape(8.dp))
                    .background(if (isSelected) MoradoNeon else SuperficieCards)
                    .clickable { onDiaClick(dia) }
                    .padding(horizontal = 12.dp, vertical = 8.dp)
            ) {
                Text(
                    text = dia,
                    color = if (isSelected) TextoBlanco else TextoGris,
                    fontSize = 14.sp
                )
            }
        }
    }
}

@Composable
fun HorariosPorDia(
    viewModel: VerHorarioViewModel,
    dia: String
) {
    val horarios = viewModel.getHorariosPorDia(dia)

    if (horarios.isEmpty()) {
        Box(
            modifier = Modifier.fillMaxSize(),
            contentAlignment = Alignment.Center
        ) {
            Text(
                text = "No hay clases este día",
                color = TextoGris,
                fontSize = 16.sp
            )
        }
    } else {
        LazyColumn(
            modifier = Modifier
                .fillMaxSize()
                .padding(horizontal = 16.dp),
            verticalArrangement = Arrangement.spacedBy(12.dp)
        ) {
            // Título del día
            item {
                Text(
                    text = "⚡ $dia",
                    fontSize = 24.sp,
                    color = MoradoNeon,
                    style = MaterialTheme.typography.headlineMedium,
                    modifier = Modifier.padding(vertical = 8.dp)
                )
            }

            // Horarios del día
            items(horarios) { horario ->
                HorarioCard(
                    horario = horario,
                    viewModel = viewModel,
                    onEliminar = {
                        viewModel.onEvent(VerHorarioEvent.EliminarHorario(horario.id))
                    }
                )
            }

            // Espacio al final
            item { Spacer(modifier = Modifier.height(20.dp)) }
        }
    }
}

@Composable
fun HorarioCard(
    horario: com.example.organizadoracademico.domain.model.Horario,
    viewModel: VerHorarioViewModel,
    onEliminar: () -> Unit
) {
    val materiaNombre = viewModel.getNombreMateria(horario.materiaId)
    val profesorNombre = viewModel.getNombreProfesor(horario.profesorId)
    val icono = viewModel.getIconoMateria(horario.materiaId)
    val color = when (viewModel.getColorMateria(horario.materiaId)) {
        "Morado" -> MoradoNeon
        "Azul" -> AzulElectrico
        "Verde" -> VerdeMatrix
        "Naranja" -> NaranjaNeon
        "Rojo" -> RosaNeon
        else -> MoradoNeon
    }

    Card(
        modifier = Modifier
            .fillMaxWidth()
            .pulseEffect(true),
        shape = RoundedCornerShape(12.dp),
        colors = CardDefaults.cardColors(
            containerColor = SuperficieCards
        )
    ) {
        Column(
            modifier = Modifier
                .fillMaxWidth()
                .padding(16.dp)
        ) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                // Icono y materia
                Row(
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Box(
                        modifier = Modifier
                            .size(40.dp)
                            .clip(RoundedCornerShape(8.dp))
                            .background(color.copy(alpha = 0.2f)),
                        contentAlignment = Alignment.Center
                    ) {
                        Text(
                            text = icono,
                            fontSize = 20.sp
                        )
                    }

                    Spacer(modifier = Modifier.width(12.dp))

                    Column {
                        Text(
                            text = materiaNombre.uppercase(),
                            fontSize = 16.sp,
                            color = TextoBlanco,
                            style = MaterialTheme.typography.titleMedium
                        )
                        Text(
                            text = profesorNombre,
                            fontSize = 14.sp,
                            color = TextoGris
                        )
                    }
                }

                // Horario
                Text(
                    text = horario.horaInicio,
                    fontSize = 14.sp,
                    color = color
                )
            }

            Spacer(modifier = Modifier.height(12.dp))

            // Botón eliminar
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.End
            ) {
                Button(
                    onClick = onEliminar,
                    shape = RoundedCornerShape(8.dp),
                    colors = ButtonDefaults.buttonColors(
                        containerColor = color.copy(alpha = 0.2f)
                    ),
                    modifier = Modifier.pulseEffect(true)
                ) {
                    Text(
                        text = "ELIMINAR",
                        fontSize = 12.sp,
                        color = color
                    )
                }
            }
        }
    }
}

