package com.example.organizadoracademico.push
import android.Manifest import android.app.NotificationChannel import android.app.NotificationManager import android.content.Context import android.content.pm.PackageManager import android.os.Build import android.util.Log import androidx.core.app.NotificationCompat import androidx.core.app.NotificationManagerCompat import androidx.core.content.ContextCompat import com.example.organizadoracademico.R import com.google.firebase.messaging.FirebaseMessagingService import com.google.firebase.messaging.RemoteMessage import kotlinx.coroutines.CoroutineScope import kotlinx.coroutines.Dispatchers import kotlinx.coroutines.launch import org.koin.core.context.GlobalContext
class OrganizadorFirebaseMessagingService : FirebaseMessagingService() {
override fun onNewToken(token: String) { super.onNewToken(token)
Log.d(TAG, "TOKEN_FCM_DEL_DISPOSITIVO: $token")
CoroutineScope(Dispatchers.IO).launch { runCatching { val uploader = GlobalContext.get().get<PushTokenUploader>() uploader.uploadToken(token) } } }
override fun onMessageReceived(message: RemoteMessage) { super.onMessageReceived(message) ensureChannel()
val title = message.data["title"] ?: message.notification?.title ?: "Organizador" val body = message.data["body"] ?: message.notification?.body ?: "Tienes una notificacion"
val notification = NotificationCompat.Builder(this, CHANNEL_ID) .setSmallIcon(R.mipmap.ic_launcher) .setContentTitle(title) .setContentText(body) .setPriority(NotificationCompat.PRIORITY_HIGH) .setAutoCancel(true) .build()
if ( Build.VERSION.SDK_INT < Build.VERSION_CODES.TIRAMISU || ContextCompat.checkSelfPermission(this, Manifest.permission.POST_NOTIFICATIONS) == PackageManager.PERMISSION_GRANTED ) { NotificationManagerCompat.from(this) .notify(System.currentTimeMillis().toInt(), notification) } }
private fun ensureChannel() { if (Build.VERSION.SDK_INT < Build.VERSION_CODES.O) return
val manager = getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager val channel = NotificationChannel( CHANNEL_ID, CHANNEL_NAME, NotificationManager.IMPORTANCE_HIGH ) manager.createNotificationChannel(channel) }
companion object { private const val TAG = "FCM_TOKEN" private const val CHANNEL_ID = "organizador_push" private const val CHANNEL_NAME = "Notificaciones generales" } }

package com.example.organizadoracademico.push

import com.example.organizadoracademico.data.local.util.SessionManager
import com.example.organizadoracademico.data.remote.ApiService
import com.example.organizadoracademico.data.remote.dto.PushTokenRequestDto

interface PushTokenUploader {
    suspend fun uploadToken(token: String)
}

class PushTokenUploaderImpl(
    private val apiService: ApiService,
    private val sessionManager: SessionManager
) : PushTokenUploader {

    override suspend fun uploadToken(token: String) {
        if (!sessionManager.isLoggedIn() || token.isBlank()) return

        val payload = PushTokenRequestDto(token = token)

        // Intentamos endpoint principal y fallback para compatibilidad.
        val primary = runCatching { apiService.registerPushToken(payload) }.getOrNull()
        if (primary?.isSuccessful == true) return

        runCatching { apiService.registerDeviceToken(payload) }
    }
}

